local TpPenGroup = Tabs.Teleports:AddLeftGroupbox("Cercado ")
TpPenGroup:AddButton({
    Text="→ Meu Cercado ",
    Func=function()
        local root = game.Players.LocalPlayer.Character and game.Players.LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
        if not root then return end
        local pen = M.findMyPen()
        if pen then
            local pos = M.getPenBasePosition()
            if pos then root.CFrame=CFrame.new(pos) end
            Library:Notify({Title="Teleportado ",Description="Caneta #"..pen.Name.." ",Time=2})
        else
            Library:Notify({Title="Erro ",Description="Cercado não encontrado! ",Time=2})
        end
    end,
})
TpPenGroup:AddButton({
    Text="→ Primeiro Pet do Cercado ",
    Func=function()
        local root = game.Players.LocalPlayer.Character and game.Players.LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
        if not root then return end
        local pets = M.getMyPenPets()
        if #pets==0 then Library:Notify({Title="Cercado ",Description="Nenhum pet no cercado. ",Time=2}) return end
        local part = pets[1]:FindFirstChildWhichIsA("BasePart")
        if part then
            root.CFrame=CFrame.new(part.Position+Vector3.new(0,3,0))
            local info = {name=pets[1]:GetAttribute("Name") or pets[1].Name}
            Library:Notify({Title="Teleportado ",Description=info.name.." ",Time=2})
        end
    end,
})

