    M.AutoCatchState.Enabled             = false
    M.ManualCatchState.Enabled           = false
    M.PenManagerState.AutoFeedEnabled    = false
    M.PenManagerState.AutoPlaceEnabled   = false
    M.PenManagerState.AutoCollectEnabled = false
    M.AutoBuyState.Enabled               = false
    M.ESPState.Enabled                   = false
    M.MovementState.FlyEnabled           = false
    M.stopCameraFly()
    M.stopWatching()
    M.clearESP()
    Library:Unload()
end)

